insomnia.test('status API returns 200', () => {
  insomnia.expect(insomnia.response.status).to.eql(200);
});

const body = insomnia.response.json();

insomnia.test('status body is JSON', () => {
  insomnia.expect(body).to.be.an('object');
});

insomnia.test('Admin API returns 200', () => {
  insomnia.expect(insomnia.response.status).to.eql(200);
});

const body = insomnia.response.json();

insomnia.test('Kong version is 3.4.2', () => {
  insomnia.expect(body.version).to.eql('3.4.2');
});

insomnia.test('enabled plugins endpoint returns 200', () => {
  insomnia.expect(insomnia.response.status).to.eql(200);
});

const enabled = JSON.stringify(insomnia.response.json());

['request-profiler', 'json-field-guard', 'canary-header-router'].forEach((plugin) => {
  insomnia.test(plugin + ' is enabled', () => {
    insomnia.expect(enabled).to.include(plugin);
  });
});

function responseHeader(name) {
  const wanted = name.toLowerCase();
  const header = (insomnia.response.headers || []).find((candidate) => {
    const key = candidate.key || candidate.name || '';
    return key.toLowerCase() === wanted;
  });
  return header ? header.value : undefined;
}

function requestHeader(headers, name) {
  const wanted = name.toLowerCase();
  const key = Object.keys(headers || {}).find((candidate) => candidate.toLowerCase() === wanted);
  return key ? headers[key] : undefined;
}

insomnia.test('proxy returns 200', () => {
  insomnia.expect(insomnia.response.status).to.eql(200);
});

insomnia.test('request-profiler response headers are present', () => {
  insomnia.expect(responseHeader('X-Kong-Elapsed')).to.match(/^\d+(\.\d+)?ms$/);
  insomnia.expect(responseHeader('X-Request-Id')).to.eql('postman-request-profiler');
});

insomnia.test('canary plugin also annotates the response', () => {
  insomnia.expect(responseHeader('X-Release-Decision')).to.match(/^(stable|canary)$/);
});

const body = insomnia.response.json();

insomnia.test('upstream echo received the proxied request', () => {
  insomnia.expect(body.method).to.eql('GET');
  insomnia.expect(body.path).to.eql('/anything/get');
  insomnia.expect(requestHeader(body.headers, 'X-Request-Id')).to.eql('postman-request-profiler');
});

