insomnia.test('guard stripped /guarded and upstream received JSON', () => {
  insomnia.expect(body.path).to.eql('/post');
  insomnia.expect(body.json.customer_id).to.eql('cust-123');
  insomnia.expect(body.json.action).to.eql('signup');
